// Define a struct to hold the popcount-depth for each number
type PopcountDepth struct {
	value    int64
	depth    int
}

// Function to calculate the popcount-depth of a number
func calculatePopcountDepth(x int64) int {
	depth := 0
	for x > 0 {
		x = popcount(x)
		depth++
	}
	return depth
}

// Function to calculate the popcount of a number
func popcount(x int64) int {
	count := 0
	for x > 0 {
		count += int(x & 1)
		x >>= 1
	}
	return count
}

// Segment Tree node
type SegmentTreeNode struct {
	left   *SegmentTreeNode
	right  *SegmentTreeNode
	start  int
	end    int
	counts [6]int // counts for depth 0 to 5
}

// Segment Tree
type SegmentTree struct {
	root *SegmentTreeNode
}

// Build the segment tree
func buildSegmentTree(start, end int, nums []int64) *SegmentTreeNode {
	if start == end {
		node := &SegmentTreeNode{
			start: start,
			end:   end,
		}
		depth := calculatePopcountDepth(nums[start])
		if depth <= 5 {
			node.counts[depth]++
		}
		return node
	}

	mid := (start + end) / 2
	left := buildSegmentTree(start, mid, nums)
	right := buildSegmentTree(mid+1, end, nums)
	node := &SegmentTreeNode{
		left:   left,
		right:  right,
		start:  start,
		end:    end,
	}
	// Merge counts
	for i := 0; i < 6; i++ {
		node.counts[i] = left.counts[i] + right.counts[i]
	}
	return node
}

// Query the segment tree for the count of numbers with a specific depth in a range
func (st *SegmentTree) query(start, end, depth int) int {
	return queryHelper(st.root, start, end, depth)
}

func queryHelper(node *SegmentTreeNode, queryStart, queryEnd, depth int) int {
	if node == nil {
		return 0
	}
	if node.start >= queryStart && node.end <= queryEnd {
		return node.counts[depth]
	}
	return queryHelper(node.left, queryStart, queryEnd, depth) + queryHelper(node.right, queryStart, queryEnd, depth)
}

// Update the segment tree
func (st *SegmentTree) update(index int, value int64) {
	updateHelper(st.root, index, value)
}

func updateHelper(node *SegmentTreeNode, index int, value int64) {
	if node.start == node.end {
		depth := calculatePopcountDepth(value)
		if depth <= 5 {
